@RestController
public class OAuth2ClientController {
    
    private static final String AUTHORIZATION_SERVER_URL = "https://auth-server.com/oauth/authorize";
    private static final String CLIENT_ID = "your-client-id";
    private static final String REDIRECT_URI = "http://localhost:8080/oauth2/callback";
    private static final String SCOPE = "read write";
    private static final String RESPONSE_TYPE = "code";
    
    @GetMapping("/login")
    public ResponseEntity<String> redirectToAuthorizationServer() {
        String authorizationUrl = buildAuthorizationUrl();
        return ResponseEntity.status(HttpStatus.FOUND)
                .header("Location", authorizationUrl)
                .build();
    }
    
    @GetMapping("/oauth2/callback")
    public ResponseEntity<String> handleCallback(@RequestParam String code) {
        // Handle the authorization code here
        return ResponseEntity.ok("Authorization successful. Code: " + code);
    }
    
    private String buildAuthorizationUrl() {
        StringBuilder urlBuilder = new StringBuilder(AUTHORIZATION_SERVER_URL);
        urlBuilder.append("?client_id=").append(CLIENT_ID);
        urlBuilder.append("&redirect_uri=").append(REDIRECT_URI);
        urlBuilder.append("&scope=").append(SCOPE);
        urlBuilder.append("&response_type=").append(RESPONSE_TYPE);
        return urlBuilder.toString();
    }
}